using CarRent.DAL;
using CarRent.Model.Entities;
using CarRent.Model.Enums;
using CarRent.Web.ViewModels;
using Microsoft.EntityFrameworkCore;

namespace CarRent.Web.Repositories;

public sealed class BranchOfficeRepository(CarRentDbContext db)
{
    public async Task<IReadOnlyList<BranchOffice>> GetAllAsync()
        => await db.BranchOffices.AsNoTracking().ToListAsync();

    public async Task<BranchOffice?> GetByIdAsync(int id)
        => await db.BranchOffices
            .Include(b => b.Vehicles)
            .AsNoTracking()
            .FirstOrDefaultAsync(b => b.Id == id);
}

public sealed class VehicleRepository(CarRentDbContext db)
{
    public async Task<IReadOnlyList<Vehicle>> GetAllAsync()
        => await db.Vehicles.AsNoTracking().ToListAsync();

    public async Task<Vehicle?> GetByIdAsync(int id)
        => await db.Vehicles
            .Include(v => v.ServiceRecords)
            .Include(v => v.BranchOffice)
            .AsNoTracking()
            .FirstOrDefaultAsync(v => v.Id == id);

    public async Task<Vehicle?> GetByRegistrationAsync(string registration)
        => await db.Vehicles
            .Include(v => v.ServiceRecords)
            .Include(v => v.BranchOffice)
            .AsNoTracking()
            .FirstOrDefaultAsync(v => v.RegistrationNumber == registration);
}

public sealed class CustomerRepository(CarRentDbContext db)
{
    public async Task<IReadOnlyList<Customer>> GetAllAsync()
        => await db.Customers.AsNoTracking().ToListAsync();

    public async Task<Customer?> GetByIdAsync(int id)
        => await db.Customers
            .Include(c => c.Reservations)
            .AsNoTracking()
            .FirstOrDefaultAsync(c => c.Id == id);
}

public sealed class ReservationRepository(CarRentDbContext db)
{
    public async Task<IReadOnlyList<Reservation>> GetAllAsync()
        => await db.Reservations.AsNoTracking().ToListAsync();

    public async Task<Reservation?> GetByIdAsync(int id)
        => await db.Reservations
            .Include(r => r.Addons)
            .Include(r => r.Customer)
            .Include(r => r.Vehicle)
            .AsNoTracking()
            .FirstOrDefaultAsync(r => r.Id == id);
}

public sealed class AddonRepository(CarRentDbContext db)
{
    public async Task<IReadOnlyList<Addon>> GetAllAsync()
        => await db.Addons.AsNoTracking().ToListAsync();

    public async Task<Addon?> GetByIdAsync(int id)
        => await db.Addons.AsNoTracking().FirstOrDefaultAsync(a => a.Id == id);
}

public sealed class ServiceRecordRepository(CarRentDbContext db)
{
    public async Task<IReadOnlyList<ServiceRecord>> GetAllAsync()
        => await db.ServiceRecords.AsNoTracking().ToListAsync();

    public async Task<ServiceRecord?> GetByIdAsync(int id)
        => await db.ServiceRecords.AsNoTracking().FirstOrDefaultAsync(s => s.Id == id);
}

public sealed class EmployeeRepository(CarRentDbContext db)
{
