[Route("partneri")]
public sealed class PartnersController(PartnerRepository repository) : Controller
{
    public async Task<IActionResult> Index()
    {
        ViewData["Title"] = "Partneri";
        ViewData["Breadcrumbs"] = BreadcrumbHelper.Build("Home", "Partneri");
        return View(await repository.GetAllAsync());
    }

    [Route("novi")]
    public IActionResult Create() => View(new Partner());

    [HttpPost]
    [Route("novi")]
    [ValidateAntiForgeryToken]
    public async Task<IActionResult> Create(Partner model)
    {
        if (!ModelState.IsValid) return View(model);
        await repository.AddAsync(model);
        return RedirectToAction(nameof(Index));
    }

    [Route("uredi/{id:int}")]
    public async Task<IActionResult> Edit(int id)
    {
        var model = await repository.GetByIdAsync(id);
        if (model is null) return NotFound();
        ViewData["Title"] = "Uredi partnera";
        return View(model);
    }

    [HttpPost]
    [Route("uredi/{id:int}")]
    [ValidateAntiForgeryToken]
    public async Task<IActionResult> Edit(int id, Partner model)
    {
        if (id != model.Id) return BadRequest();
        if (!ModelState.IsValid) return View(model);
        await repository.UpdateAsync(model);
        return RedirectToAction(nameof(Index));
    }

    [HttpPost]
    [Route("obrisi/{id:int}")]
    [ValidateAntiForgeryToken]
    public async Task<IActionResult> Delete(int id)
    {
        await repository.DeleteAsync(id);
        return RedirectToAction(nameof(Index));
    }
}

